<?php $rows=$fleet['rows']??[];$clients=$fleet['clients']??[];$brands=$fleet['brands']??[];$families=$fleet['families']??[];$models=$fleet['models']??[];$standards=$fleet['standards']??[];$metrics=$fleet['metrics']??['vehicles'=>0,'brands'=>0,'videos'=>0];$page=$fleet['page']??1;$perPage=$fleet['perPage']??10;$offset=$fleet['offset']??0;$totalRows=$fleet['totalRows']??0;$totalPages=$fleet['totalPages']??1;$q=$fleet['q']??'';$brandFilter=$fleet['brandFilter']??0;$familyFilter=$fleet['familyFilter']??0;$standardFilter=$fleet['standardFilter']??0;$clientFilter=$fleet['clientFilter']??0;$isClient=(user()['active_company_type']??'')==='cliente'; ?>
<section class="page-heading split"><div><span class="eyebrow blue">Gestão de veículos</span><h1><?= $isClient?'Minha frota':'Frotas dos clientes' ?></h1><p><?= $isClient?'Cadastre veículos Volkswagen e de outras marcas. Modelos ainda não catalogados podem ser informados manualmente.':'Consulte e mantenha as frotas multimarcas dos clientes no seu escopo.' ?></p></div><?php if(can('fleet','create')&&($clients||$isClient)): ?><button class="btn primary" data-fleet-create><i class="bi bi-plus-lg"></i> Adicionar composição</button><?php endif; ?></section>
<?php if($flash): ?><div class="alert <?= $flash['type']==='success'?'success':'error' ?>"><i class="bi <?= $flash['type']==='success'?'bi-check-circle':'bi-exclamation-circle' ?>"></i> <?= e($flash['message']) ?></div><?php endif; ?>
<section class="metrics mini"><article class="metric"><span class="metric-icon blue"><i class="bi bi-truck"></i></span><div><small>Total de veículos</small><strong><?= number_format((int)$metrics['vehicles'],0,',','.') ?></strong></div></article><article class="metric"><span class="metric-icon green"><i class="bi bi-tags"></i></span><div><small>Marcas na frota</small><strong><?= (int)$metrics['brands'] ?></strong></div></article><article class="metric"><span class="metric-icon orange"><i class="bi bi-play-circle"></i></span><div><small>Vídeos compatíveis</small><strong><?= (int)$metrics['videos'] ?></strong></div></article></section>
<section class="panel"><form class="panel-head table-filters fleet-filters" method="get" action="<?= url('frota') ?>" data-brand-family-filters><div class="search"><span><i class="bi bi-search"></i></span><input type="search" name="q" value="<?= e($q) ?>" placeholder="Buscar veículo, marca, família, cliente ou norma..."></div><div class="panel-filters"><?php if(!$isClient&&count($clients)>1): ?><select name="cliente"><option value="">Todos os clientes</option><?php foreach($clients as $client): ?><option value="<?= (int)$client['id'] ?>" <?= $clientFilter===(int)$client['id']?'selected':'' ?>><?= e($client['nome_fantasia']) ?></option><?php endforeach; ?></select><?php endif; ?><select name="marca" data-filter-brand><option value="">Todas as marcas</option><?php foreach($brands as $brand): ?><option value="<?= (int)$brand['id'] ?>" <?= $brandFilter===(int)$brand['id']?'selected':'' ?>><?= e($brand['nome']) ?></option><?php endforeach; ?></select><select name="familia" data-filter-family><option value="">Todas as famílias</option><?php foreach($families as $family): ?><option value="<?= (int)$family['id'] ?>" data-brand="<?= (int)$family['marca_id'] ?>" <?= $familyFilter===(int)$family['id']?'selected':'' ?>><?= e($family['nome']) ?></option><?php endforeach; ?></select><select name="norma"><option value="">Todas as normas</option><?php foreach($standards as $standard): ?><option value="<?= (int)$standard['id'] ?>" <?= $standardFilter===(int)$standard['id']?'selected':'' ?>><?= e($standard['nome']) ?></option><?php endforeach; ?></select><button class="btn secondary"><i class="bi bi-search"></i> Buscar</button><?php if($q!==''||$brandFilter||$familyFilter||$standardFilter||(!$isClient&&$clientFilter)): ?><a class="btn secondary" href="<?= url('frota') ?>" aria-label="Limpar filtros"><i class="bi bi-x-lg"></i></a><?php endif; ?></div></form>
<div class="table-wrap"><table><thead><tr><th>Veículo</th><?php if(!$isClient): ?><th>Cliente</th><?php endif; ?><th>Ano e emissões</th><th>Quantidade</th><th>Conteúdos</th><th>Observação</th><th>Ações</th></tr></thead><tbody><?php if(!$rows): ?><tr><td colspan="<?= $isClient?6:7 ?>"><div class="table-empty"><i class="bi bi-truck"></i><strong>Nenhuma composição encontrada</strong><span>Cadastre o primeiro grupo de veículos desta frota.</span></div></td></tr><?php endif; ?>
<?php foreach($rows as $row): $payload=['id'=>(int)$row['id'],'cliente_empresa_id'=>(int)$row['cliente_empresa_id'],'marca_id'=>(int)$row['marca_id'],'familia_id'=>(int)($row['familia_id']??0),'modelo_id'=>(int)($row['modelo_id']??0),'veiculo_nome'=>$row['veiculo_nome'],'familia_nome_livre'=>$row['familia_nome_livre'],'quantidade'=>(int)$row['quantidade'],'ano'=>(int)$row['ano'],'norma_emissao_id'=>(int)$row['norma_emissao_id'],'observacao'=>$row['observacao']]; ?><tr><td><div class="entity-cell"><?php if($row['modelo_imagem']): ?><img src="<?= url($row['modelo_imagem']) ?>" alt="<?= e($row['modelo_nome']) ?>"><?php elseif($row['marca_logo']): ?><img src="<?= url($row['marca_logo']) ?>" alt="Logo <?= e($row['marca_nome']) ?>"><?php else: ?><span class="entity-placeholder"><i class="bi bi-truck-front"></i></span><?php endif; ?><div><strong><?= e($row['modelo_nome']) ?></strong><small><?= e($row['marca_nome']) ?> · <?= e($row['familia_nome']) ?></small></div></div></td><?php if(!$isClient): ?><td><strong><?= e($row['cliente_nome']) ?></strong><small>Empresa cliente</small></td><?php endif; ?><td><span class="emission-badge"><i class="bi bi-cloud-haze2"></i> <?= e($row['norma_nome']?:'Não informada') ?></span><small>Ano <?= (int)$row['ano'] ?></small></td><td><strong><?= number_format((int)$row['quantidade'],0,',','.') ?></strong><small>veículo(s)</small></td><td><strong><?= (int)$row['videos'] ?> vídeo(s)</strong><small><?= $row['modelo_id']?'Família e modelo':'Aguardando catalogação' ?></small></td><td class="description-cell"><?= e($row['observacao']?:'Sem observação') ?></td><td><div class="row-actions"><?php if(can('fleet','update')): ?><button class="action-btn" data-fleet-edit data-fleet="<?= e(json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)) ?>" aria-label="Editar <?= e($row['modelo_nome']) ?>"><i class="bi bi-pencil"></i></button><?php endif; ?><?php if(can('fleet','delete')): ?><button class="action-btn danger" data-fleet-delete data-id="<?= (int)$row['id'] ?>" data-name="<?= e($row['modelo_nome'].' · '.$row['ano']) ?>" aria-label="Excluir composição"><i class="bi bi-trash"></i></button><?php endif; ?></div></td></tr><?php endforeach; ?></tbody></table></div>
<div class="pagination"><form method="get" action="<?= url('frota') ?>" class="per-page"><input type="hidden" name="q" value="<?= e($q) ?>"><input type="hidden" name="cliente" value="<?= (int)$clientFilter ?>"><input type="hidden" name="marca" value="<?= (int)$brandFilter ?>"><input type="hidden" name="familia" value="<?= (int)$familyFilter ?>"><input type="hidden" name="norma" value="<?= (int)$standardFilter ?>"><label>Mostrar <select name="per_page" onchange="this.form.submit()"><?php foreach([5,10,25,50] as $size): ?><option value="<?= $size ?>" <?= $perPage===$size?'selected':'' ?>><?= $size ?></option><?php endforeach; ?></select> linhas</label></form><span>Mostrando <?= $totalRows?$offset+1:0 ?>–<?= min($offset+$perPage,$totalRows) ?> de <?= $totalRows ?></span><nav class="page-buttons"><?php if($page>1): ?><a href="<?= page_url('frota',['page'=>$page-1]) ?>"><i class="bi bi-chevron-left"></i></a><?php endif; ?><?php for($p=max(1,$page-2);$p<=min($totalPages,$page+2);$p++): ?><a class="<?= $p===$page?'active':'' ?>" href="<?= page_url('frota',['page'=>$p]) ?>"><?= $p ?></a><?php endfor; ?><?php if($page<$totalPages): ?><a href="<?= page_url('frota',['page'=>$page+1]) ?>"><i class="bi bi-chevron-right"></i></a><?php endif; ?></nav></div></section>
<div class="modal" id="fleet-modal" aria-hidden="true"><div class="modal-dialog access-dialog fleet-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="eyebrow blue">Composição da frota</span><h2 data-fleet-modal-title>Adicionar veículos</h2><p>Selecione um modelo do catálogo ou informe manualmente um veículo ainda não catalogado.</p><form method="post" data-fleet-form><?= csrf_field() ?><input type="hidden" name="action" value="create"><input type="hidden" name="id"><div class="form-grid"><?php if(!$isClient): ?><label class="full">Empresa cliente<select name="cliente_empresa_id" required><option value="">Selecione o cliente</option><?php foreach($clients as $client): ?><option value="<?= (int)$client['id'] ?>"><?= e($client['nome_fantasia']) ?></option><?php endforeach; ?></select></label><?php endif; ?><label class="full">Marca<select name="marca_id" data-fleet-brand required><option value="">Selecione a marca</option><?php foreach($brands as $brand): ?><option value="<?= (int)$brand['id'] ?>"><?= e($brand['nome']) ?></option><?php endforeach; ?></select></label><label>Família <small>(opcional)</small><select name="familia_id" data-fleet-family><option value="">Não catalogada / não informar</option><?php foreach($families as $family): ?><option value="<?= (int)$family['id'] ?>" data-brand="<?= (int)$family['marca_id'] ?>"><?= e($family['nome']) ?></option><?php endforeach; ?></select></label><label>Modelo catalogado <small>(opcional)</small><select name="modelo_id" data-fleet-model><option value="">Não catalogado / informar abaixo</option><?php foreach($models as $model): ?><option value="<?= (int)$model['id'] ?>" data-brand="<?= (int)$model['marca_id'] ?>" data-family="<?= (int)$model['familia_id'] ?>"><?= e($model['nome']) ?></option><?php endforeach; ?></select></label><label class="full" data-fleet-free-model>Modelo ou identificação do veículo<input name="veiculo_nome" maxlength="160" placeholder="Ex.: S-Way 480 6x2 ou veículo 07"><small>Use este campo somente quando o modelo ainda não existir no catálogo.</small></label><label class="full" data-fleet-free-family>Família/linha informada pelo cliente <small>(opcional)</small><input name="familia_nome_livre" maxlength="120" placeholder="Ex.: S-Way"></label><label>Quantidade de veículos<input type="number" name="quantidade" min="1" max="100000" value="1" required></label><label>Ano da frota<input type="number" name="ano" min="1950" max="<?= (int)date('Y')+2 ?>" value="<?= (int)date('Y') ?>" required></label><label class="full">Norma de emissões<select name="norma_emissao_id" required><option value="">Selecione a norma</option><?php foreach($standards as $standard): ?><option value="<?= (int)$standard['id'] ?>"><?= e($standard['nome']) ?> — <?= e($standard['codigo']) ?></option><?php endforeach; ?></select></label><label class="full">Observação<textarea name="observacao" rows="3" maxlength="1000"></textarea></label></div><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn primary"><i class="bi bi-check-lg"></i> Salvar composição</button></div></form></div></div></div>
<div class="modal" id="delete-fleet-modal" aria-hidden="true"><div class="modal-dialog confirm-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="confirm-icon"><i class="bi bi-trash"></i></span><h2>Excluir composição?</h2><p>O grupo <strong data-delete-fleet-name></strong> será removido da frota.</p><form method="post"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" data-delete-fleet-id><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn danger"><i class="bi bi-trash"></i> Excluir</button></div></form></div></div></div>
